//! Loading and using custom themes from files

use lipgloss::{Theme, Style, ColorSlot};
use std::path::Path;

fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Try to load custom theme, fall back to built-in
    let theme = load_theme()?;

    let styles = AppStyles::from_theme(&theme);

    println!("{}", styles.header.render("Custom Theme Demo"));
    println!();
    println!("{}", styles.success.render("[SUCCESS] Operation completed"));
    println!("{}", styles.warning.render("[WARNING] Disk space low"));
    println!("{}", styles.error.render("[ERROR] Connection failed"));

    Ok(())
}

fn load_theme() -> Result<Theme, Box<dyn std::error::Error>> {
    let custom_path = Path::new("examples/custom-theme.toml");

    if custom_path.exists() {
        println!("Loading custom theme from {:?}", custom_path);
        Ok(Theme::from_file(custom_path)?)
    } else {
        println!("Using default Dracula theme");
        Ok(ThemePreset::Dracula.to_theme())
    }
}

struct AppStyles {
    header: Style,
    success: Style,
    warning: Style,
    error: Style,
}

impl AppStyles {
    fn from_theme(theme: &Theme) -> Self {
        Self {
            header: Style::from_theme(theme, ColorSlot::Primary)
                .bold(true)
                .underline(true),
            success: Style::from_theme(theme, ColorSlot::Success),
            warning: Style::from_theme(theme, ColorSlot::Warning),
            error: Style::from_theme(theme, ColorSlot::Error).bold(true),
        }
    }
}
```

