## Objective
Implement robust session lifecycle management including tracking, cleanup, and graceful shutdown.

## Implementation Details

### Session Registry
```rust
use std::collections::HashMap;
use std::sync::Arc;
use tokio::sync::RwLock;

pub struct SessionRegistry {
    sessions: Arc<RwLock<HashMap<SessionId, SessionInfo>>>,
    max_sessions: Option<usize>,
}

#[derive(Clone)]
pub struct SessionInfo {
    pub id: SessionId,
    pub user: String,
    pub peer_addr: SocketAddr,
    pub connected_at: Instant,
    pub last_activity: Arc<RwLock<Instant>>,
    pub channels: Vec<ChannelId>,
    pub state: SessionState,
}

#[derive(Clone, Copy, Debug, PartialEq)]
pub enum SessionState {
    Connecting,
    Authenticating,
    Active,
    Closing,
    Closed,
}

impl SessionRegistry {
    pub fn new(max_sessions: Option<usize>) -> Self {
        Self {
            sessions: Arc::new(RwLock::new(HashMap::new())),
            max_sessions,
        }
    }

    pub async fn register(&self, info: SessionInfo) -> Result<(), SessionError> {
        let mut sessions = self.sessions.write().await;

        if let Some(max) = self.max_sessions {
            if sessions.len() >= max {
                log::warn!("Max sessions ({}) reached, rejecting new connection", max);
                return Err(SessionError::MaxSessionsReached);
            }
        }

        log::info!("Session {} registered for user '{}'", info.id, info.user);
        sessions.insert(info.id.clone(), info);
        Ok(())
    }

    pub async fn unregister(&self, id: &SessionId) {
        let mut sessions = self.sessions.write().await;
        if sessions.remove(id).is_some() {
            log::info!("Session {} unregistered", id);
        }
    }

    pub async fn get(&self, id: &SessionId) -> Option<SessionInfo> {
        self.sessions.read().await.get(id).cloned()
    }

    pub async fn list_active(&self) -> Vec<SessionInfo> {
        self.sessions.read().await
            .values()
            .filter(|s| s.state == SessionState::Active)
            .cloned()
            .collect()
    }

    pub async fn count(&self) -> usize {
        self.sessions.read().await.len()
    }
}
```

### Session Cleanup
```rust
pub struct SessionCleaner {
    registry: Arc<SessionRegistry>,
    idle_timeout: Duration,
    check_interval: Duration,
}

impl SessionCleaner {
    pub fn new(
        registry: Arc<SessionRegistry>,
        idle_timeout: Duration,
        check_interval: Duration,
    ) -> Self {
        Self {
            registry,
            idle_timeout,
            check_interval,
        }
    }

    pub async fn run(&self, mut shutdown: tokio::sync::broadcast::Receiver<()>) {
        log::info!(
            "Session cleaner started (idle_timeout={:?}, check_interval={:?})",
            self.idle_timeout,
            self.check_interval
        );

        let mut interval = tokio::time::interval(self.check_interval);

        loop {
            tokio::select! {
                _ = interval.tick() => {
                    self.cleanup_idle_sessions().await;
                }
                _ = shutdown.recv() => {
                    log::info!("Session cleaner shutting down");
                    break;
                }
            }
        }
    }

    async fn cleanup_idle_sessions(&self) {
        let sessions = self.registry.sessions.read().await;
        let now = Instant::now();
        let mut to_cleanup = Vec::new();

        for (id, info) in sessions.iter() {
            let last_activity = *info.last_activity.read().await;
            if now.duration_since(last_activity) > self.idle_timeout {
                log::info!(
                    "Session {} idle for {:?}, marking for cleanup",
                    id,
                    now.duration_since(last_activity)
                );
                to_cleanup.push(id.clone());
            }
        }
        drop(sessions);

        for id in to_cleanup {
            self.force_close_session(&id).await;
        }
    }

    async fn force_close_session(&self, id: &SessionId) {
        log::warn!("Force closing session {}", id);
        // Send close signal to session handler
        // Clean up PTY, channels, etc.
        self.registry.unregister(id).await;
    }
}
```

### Graceful Shutdown
```rust
pub struct GracefulShutdown {
    registry: Arc<SessionRegistry>,
    shutdown_timeout: Duration,
}

impl GracefulShutdown {
    pub async fn shutdown(&self) -> Result<()> {
        log::info!("Initiating graceful shutdown");

        let sessions = self.registry.list_active().await;
        log::info!("Closing {} active sessions", sessions.len());

        // Notify all sessions of impending shutdown
        for session in &sessions {
            log::debug!("Notifying session {} of shutdown", session.id);
            // Send shutdown notification
        }

        // Wait for sessions to close gracefully
        let deadline = Instant::now() + self.shutdown_timeout;

        while Instant::now() < deadline {
            let remaining = self.registry.count().await;
            if remaining == 0 {
                log::info!("All sessions closed gracefully");
                return Ok(());
            }

            log::debug!("{} sessions remaining", remaining);
            tokio::time::sleep(Duration::from_millis(100)).await;
        }

        // Force close remaining sessions
        let remaining = self.registry.list_active().await;
        log::warn!("Force closing {} remaining sessions", remaining.len());

        for session in remaining {
            self.registry.unregister(&session.id).await;
        }

        Ok(())
    }
}
```

