   // Change:
   struct MyModel { ... }

   // To:
   #[derive(Model)]
   struct MyModel { ... }
   ```

2. Move trait impl to inherent impl:
   ```rust
   // Change:
   impl Model for MyModel {
       fn init() -> ... { ... }
   }

   // To:
   impl MyModel {
       #[init]
       fn init() -> ... { ... }
   }
   ```

3. Add #[state] to render-triggering fields:
   ```rust
   #[derive(Model)]
   struct MyModel {
       #[state]  // Add this
       count: i32,

       cache: HashMap<K, V>,  // No #[state] = not tracked
   }
   ```

